CREATE TABLE "public"."goods_search" (
  "id" uuid NOT NULL,
  "good_id" varchar NOT NULL,
  "group_id" uuid NOT NULL,
  "game" int2 NOT NULL,
  "display_name" text NOT NULL,
  "original_name" text NOT NULL,
  "image_id" text NOT NULL,
  "status" int2 NOT NULL,
  "has_offers" bool NOT NULL DEFAULT false,
  "features" jsonb NOT NULL,
  "prices" jsonb NOT NULL,
  "number_of_sales_per_week" int4 NOT NULL,
  "avg_price_for_week_rub" numeric NOT NULL,
  "avg_price_for_week_usd" numeric NOT NULL,
  "avg_price_for_week_eur" numeric NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT now(),
  "updated_at" timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY ("id")
);

CREATE TABLE "public"."stores" (
    "id" uuid NOT NULL,
    "owner_id" varchar NOT NULL,
    "status" int2 NOT NULL,
    "alias" text NOT NULL,
    "total_deals" int4 NOT NULL DEFAULT 0,
    "active_deals" int4 NOT NULL DEFAULT 0,
    "feedbacks" int4 NOT NULL DEFAULT 0,
    "deals_duration" int4 NOT NULL DEFAULT 0,
    "rating" numeric NOT NULL DEFAULT 0,
    "is_online" bool NOT NULL DEFAULT false,
    "online_changed_at" timestamptz,
    "disabled_by" varchar,
    "created_at" timestamptz NOT NULL,
    "updated_at" timestamptz NOT NULL,
    PRIMARY KEY ("id")
);

CREATE TABLE "public"."stores_search" (
  "item_id" uuid NOT NULL,
  "game" int2 NOT NULL,
  "good_id" uuid NOT NULL,
  "good_name" text NOT NULL,
  "store_id" uuid NOT NULL,
  "account_id" uuid NOT NULL,
  "status" int2 NOT NULL,
  "comment" jsonb NOT NULL,
  "prices" jsonb NOT NULL,
  "store_status" int2 NOT NULL,
  "store_online" bool NOT NULL DEFAULT false,
  "store_rating" numeric NOT NULL,
  "store_feedbacks" int4 NOT NULL,
  "store_duration" int4 NOT NULL,
  "store_created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY ("item_id")
);

CREATE TABLE "public"."stores_prices" (
  "item_id" uuid NOT NULL,
  "good_id" uuid NOT NULL,
  "rub" numeric NOT NULL,
  "usd" numeric NOT NULL,
  "eur" numeric NOT NULL,
  "base_price" numeric NOT NULL DEFAULT 0,
  "currency" varchar NOT NULL,
  "country" varchar,
  "coefficient" varchar NOT NULL DEFAULT '000'::character varying,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("item_id","coefficient")
);




